#!/usr/bin/env node

import { createInterface } from "node:readline/promises";
import { stdin, stdout, argv } from "node:process";
import { existsSync, mkdirSync, readFileSync, writeFileSync, copyFileSync } from "node:fs";
import { join, dirname, relative } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const PKG_ROOT = join(__dirname, "..");
const CWD = process.cwd();

const FRAMEWORKS = [
  { key: "react", name: "React / Next.js", skill: "frontloom-react.md", snippet: "react.code-snippets" },
  { key: "vue", name: "Vue / Nuxt", skill: "frontloom-vue.md", snippet: "vue.code-snippets" },
  { key: "svelte", name: "Svelte / SvelteKit", skill: "frontloom-svelte.md", snippet: "svelte.code-snippets" },
  { key: "angular", name: "Angular", skill: "frontloom-angular.md", snippet: "angular.code-snippets" },
  { key: "astro", name: "Astro", skill: "frontloom-astro.md", snippet: "astro.code-snippets" },
];

const RESET = "\x1b[0m";
const BOLD = "\x1b[1m";
const DIM = "\x1b[2m";
const GREEN = "\x1b[32m";
const CYAN = "\x1b[36m";
const YELLOW = "\x1b[33m";
const RED = "\x1b[31m";

function log(msg) { console.log(msg); }
function success(msg) { log(`${GREEN}✓${RESET} ${msg}`); }
function warn(msg) { log(`${YELLOW}!${RESET} ${msg}`); }
function info(msg) { log(`${DIM}${msg}${RESET}`); }

function detectFramework() {
  const pkgPath = join(CWD, "package.json");
  if (!existsSync(pkgPath)) return null;

  const pkg = JSON.parse(readFileSync(pkgPath, "utf-8"));
  const allDeps = { ...pkg.dependencies, ...pkg.devDependencies };

  if (allDeps["next"]) return "react";
  if (allDeps["nuxt"]) return "vue";
  if (allDeps["@sveltejs/kit"] || allDeps["svelte"]) return "svelte";
  if (allDeps["@angular/core"]) return "angular";
  if (allDeps["astro"]) return "astro";
  if (allDeps["react"]) return "react";
  if (allDeps["vue"]) return "vue";

  return null;
}

function detectTool() {
  if (existsSync(join(CWD, ".claude"))) return "claude";
  if (existsSync(join(CWD, "CLAUDE.md"))) return "claude";
  if (existsSync(join(CWD, ".opencode"))) return "opencode";
  return "claude"; // default
}

function getFrontloomPath() {
  // Check if we're in node_modules (installed as dependency)
  const nmPath = join(CWD, "node_modules", "frontloom");
  if (existsSync(nmPath)) {
    return relative(CWD, nmPath).replace(/\\/g, "/");
  }
  // Check if frontloom is the current directory (development)
  if (existsSync(join(CWD, "skills", "frontloom-core-fe.md"))) {
    return ".";
  }
  return "node_modules/frontloom";
}

async function promptChoice(rl, question, choices) {
  log("");
  log(`${BOLD}${question}${RESET}`);
  choices.forEach((c, i) => {
    log(`  ${CYAN}${i + 1}${RESET}) ${c.name}${c.hint ? ` ${DIM}${c.hint}${RESET}` : ""}`);
  });

  while (true) {
    const answer = await rl.question(`\n  ${DIM}Pick [1-${choices.length}]:${RESET} `);
    const idx = parseInt(answer, 10) - 1;
    if (idx >= 0 && idx < choices.length) return choices[idx];
    log(`  ${RED}Invalid choice. Enter a number between 1 and ${choices.length}.${RESET}`);
  }
}

async function promptYesNo(rl, question, defaultYes = true) {
  const hint = defaultYes ? "[Y/n]" : "[y/N]";
  const answer = await rl.question(`\n${BOLD}${question}${RESET} ${DIM}${hint}${RESET} `);
  const normalized = answer.trim().toLowerCase();
  if (normalized === "") return defaultYes;
  return normalized === "y" || normalized === "yes";
}

function ensureDir(dirPath) {
  if (!existsSync(dirPath)) {
    mkdirSync(dirPath, { recursive: true });
  }
}

function writeJson(filePath, data) {
  writeFileSync(filePath, JSON.stringify(data, null, 2) + "\n", "utf-8");
}

function setupClaudeSettings(frontloomPath, framework) {
  const claudeDir = join(CWD, ".claude");
  ensureDir(claudeDir);

  const settingsPath = join(claudeDir, "settings.json");
  let settings = {};

  if (existsSync(settingsPath)) {
    try {
      settings = JSON.parse(readFileSync(settingsPath, "utf-8"));
    } catch {
      warn("Existing .claude/settings.json is invalid, creating new one");
      settings = {};
    }
  }

  const corePath = `${frontloomPath}/skills/frontloom-core-fe.md`;
  const fwPath = `${frontloomPath}/skills/${framework.skill}`;

  const existingSkills = settings.skills || [];
  const newSkills = [...existingSkills];

  // Remove old frontloom skills if present
  const filtered = newSkills.filter(
    (s) => !s.includes("frontloom-core-fe") && !s.includes("frontloom-react") &&
           !s.includes("frontloom-vue") && !s.includes("frontloom-svelte") &&
           !s.includes("frontloom-angular") && !s.includes("frontloom-astro")
  );

  filtered.push(corePath, fwPath);
  settings.skills = filtered;

  writeJson(settingsPath, settings);
  return settingsPath;
}

function setupOpencode(frontloomPath, framework) {
  const opencodeDir = join(CWD, ".opencode");
  ensureDir(opencodeDir);

  const instructionsPath = join(opencodeDir, "instructions.md");

  let content = "";
  if (existsSync(instructionsPath)) {
    content = readFileSync(instructionsPath, "utf-8");
    // Remove old frontloom section if present
    content = content.replace(/## Frontloom Frontend Standards[\s\S]*?(?=\n## |\n*$)/g, "").trim();
    content += "\n\n";
  }

  content += `## Frontloom Frontend Standards

Before writing any frontend code, read and follow these files:

1. \`${frontloomPath}/skills/frontloom-core-fe.md\` — baseline quality standards
2. \`${frontloomPath}/skills/${framework.skill}\` — ${framework.name} patterns

When these skills reference a file in \`references/\`, read it from \`${frontloomPath}/references/\`.
Before finishing frontend work, review against \`${frontloomPath}/references/review-checklist.md\`.
`;

  writeFileSync(instructionsPath, content.trim() + "\n", "utf-8");
  return instructionsPath;
}

function copySnippet(framework) {
  const vscodeDir = join(CWD, ".vscode");
  ensureDir(vscodeDir);

  const srcPath = join(PKG_ROOT, "snippets", framework.snippet);
  const destPath = join(vscodeDir, `frontloom-${framework.key}.code-snippets`);

  if (!existsSync(srcPath)) {
    warn(`Snippet file not found: ${framework.snippet}`);
    return null;
  }

  copyFileSync(srcPath, destPath);
  return destPath;
}

async function main() {
  // Handle --help
  if (argv.includes("--help") || argv.includes("-h")) {
    log(`
${BOLD}frontloom init${RESET}

Set up Frontloom frontend skill plugins in your project.

${BOLD}Usage:${RESET}
  npx frontloom init              Interactive setup
  npx frontloom init --yes        Accept defaults (auto-detect framework)
  npx frontloom init --framework react   Skip framework prompt
  npx frontloom init --tool claude       Skip tool prompt

${BOLD}Options:${RESET}
  --yes, -y           Accept all defaults
  --framework, -f     Framework: react, vue, svelte, angular, astro
  --tool, -t          Tool: claude, opencode
  --no-snippets       Skip VS Code snippet installation
  --help, -h          Show this help
`);
    process.exit(0);
  }

  const isYes = argv.includes("--yes") || argv.includes("-y");
  const noSnippets = argv.includes("--no-snippets");

  // Parse --framework flag
  let flagFramework = null;
  const fwIdx = argv.indexOf("--framework") !== -1 ? argv.indexOf("--framework") : argv.indexOf("-f");
  if (fwIdx !== -1 && argv[fwIdx + 1]) {
    flagFramework = argv[fwIdx + 1];
  }

  // Parse --tool flag
  let flagTool = null;
  const toolIdx = argv.indexOf("--tool") !== -1 ? argv.indexOf("--tool") : argv.indexOf("-t");
  if (toolIdx !== -1 && argv[toolIdx + 1]) {
    flagTool = argv[toolIdx + 1];
  }

  log("");
  log(`${BOLD}${CYAN}Frontloom${RESET} ${BOLD}— Frontend Skill Plugins${RESET}`);
  log(`${DIM}Setting up expert-level frontend standards for your project.${RESET}`);

  const rl = createInterface({ input: stdin, output: stdout });

  try {
    // 1. Detect or ask framework
    const detected = detectFramework();
    let framework;

    if (flagFramework) {
      framework = FRAMEWORKS.find((f) => f.key === flagFramework);
      if (!framework) {
        log(`${RED}Unknown framework: ${flagFramework}${RESET}`);
        log(`Available: ${FRAMEWORKS.map((f) => f.key).join(", ")}`);
        process.exit(1);
      }
      info(`Framework: ${framework.name} (from --framework flag)`);
    } else if (isYes && detected) {
      framework = FRAMEWORKS.find((f) => f.key === detected);
      info(`Auto-detected framework: ${framework.name}`);
    } else {
      const choices = FRAMEWORKS.map((f) => ({
        ...f,
        hint: f.key === detected ? "(detected)" : "",
      }));

      // Move detected framework to top
      if (detected) {
        const idx = choices.findIndex((c) => c.key === detected);
        if (idx > 0) {
          const [item] = choices.splice(idx, 1);
          choices.unshift(item);
        }
      }

      framework = await promptChoice(rl, "Which framework does this project use?", choices);
    }

    // 2. Detect or ask tool
    const detectedTool = flagTool || detectTool();
    let tool;

    if (flagTool || isYes) {
      tool = detectedTool;
      info(`Tool: ${tool === "claude" ? "Claude Code" : "OpenCode"}`);
    } else {
      const toolChoice = await promptChoice(rl, "Which AI coding tool are you using?", [
        { key: "claude", name: "Claude Code", hint: "(CLI, VS Code, JetBrains)" },
        { key: "opencode", name: "OpenCode" },
      ]);
      tool = toolChoice.key;
    }

    // 3. Ask about snippets
    let installSnippets;
    if (noSnippets) {
      installSnippets = false;
    } else if (isYes) {
      installSnippets = true;
    } else {
      installSnippets = await promptYesNo(rl, "Install VS Code snippets?");
    }

    rl.close();

    // Execute
    log("");
    log(`${BOLD}Setting up...${RESET}`);

    const frontloomPath = getFrontloomPath();

    // 4. Set up tool config
    if (tool === "claude") {
      const settingsPath = setupClaudeSettings(frontloomPath, framework);
      success(`Configured ${relative(CWD, settingsPath)}`);
    } else {
      const instructionsPath = setupOpencode(frontloomPath, framework);
      success(`Configured ${relative(CWD, instructionsPath)}`);
    }

    // 5. Copy snippets
    if (installSnippets) {
      const snippetPath = copySnippet(framework);
      if (snippetPath) {
        success(`Copied snippets → ${relative(CWD, snippetPath)}`);
        info(`Type "fl-" in VS Code to use Frontloom snippets.`);
      }
    }

    // Done
    log("");
    log(`${GREEN}${BOLD}Done!${RESET} Frontloom is ready.`);
    log("");
    log(`${BOLD}What's configured:${RESET}`);
    log(`  ${DIM}Baseline:${RESET}  frontloom-core-fe ${DIM}(semantics, a11y, TypeScript, security, responsive)${RESET}`);
    log(`  ${DIM}Framework:${RESET} frontloom-${framework.key} ${DIM}(${framework.name} patterns)${RESET}`);
    if (installSnippets) {
      log(`  ${DIM}Snippets:${RESET}  fl-* ${DIM}(type "fl-" in VS Code)${RESET}`);
    }
    log("");
    log(`${DIM}Guides:${RESET}`);
    log(`  ${DIM}Full setup:${RESET}        ${frontloomPath}/USAGE.md`);
    log(`  ${DIM}ESLint alignment:${RESET}  ${frontloomPath}/guides/eslint-prettier.md`);
    log(`  ${DIM}Monorepo setup:${RESET}    ${frontloomPath}/guides/monorepo.md`);
    log("");

  } catch (err) {
    rl.close();
    if (err.code === "ERR_USE_AFTER_CLOSE") {
      // User pressed Ctrl+C
      log("\n\nAborted.");
      process.exit(0);
    }
    throw err;
  }
}

main().catch((err) => {
  console.error(`${RED}Error:${RESET} ${err.message}`);
  process.exit(1);
});
